+import Clutter from 'gi://Clutter';
+import St from 'gi://St';
+
+export class InputRouter {
+    constructor(windowGroup, display) {
+        this._windowGroup = windowGroup;
+        this._display = display;
+        this._restackGuard = false;
+
+        this._stampLayer = new St.Widget({
+            name: 'mutter-butter-stamp-layer',
+            reactive: false,
+            layout_manager: new Clutter.FixedLayout(),
+        });
+        windowGroup.add_child(this._stampLayer);
+        this._raiseStampLayer();
+
+        this._restackedId = display.connect('restacked', () => {
+            if (this._restackGuard)
+                return;
+            this._restackGuard = true;
+            this._raiseStampLayer();
+            this._restackGuard = false;
+        });
+    }
+
+    _raiseStampLayer() {
+        const parent = this._stampLayer.get_parent();
+        if (parent)
+            parent.set_child_above_sibling(this._stampLayer, null);
+    }
+
+    addContainer(container, x, y) {
+        container.set_position(x, y);
+        this._stampLayer.add_child(container);
+    }
+
+    moveContainer(container, x, y) {
+        container.set_position(x, y);
+    }
+
+    removeContainer(container) {
+        if (container.get_parent() === this._stampLayer)
+            this._stampLayer.remove_child(container);
+    }
+
+    reparentForDrag(container, topWindowGroup) {
+        if (container.get_parent())
+            container.get_parent().remove_child(container);
+        topWindowGroup.add_child(container);
+    }
+
+    reparentFromDrag(container) {
+        if (container.get_parent())
+            container.get_parent().remove_child(container);
+        this._stampLayer.add_child(container);
+    }
+
+    get stampLayer() {
+        return this._stampLayer;
+    }
+
+    suspend() {
+        this._stampLayer.visible = false;
+    }
+
+    restore() {
+        this._stampLayer.visible = true;
+    }
+
+    destroy() {
+        if (this._restackedId) {
+            this._display.disconnect(this._restackedId);
+            this._restackedId = 0;
+        }
+        this._stampLayer.destroy();
+        this._stampLayer = null;
+    }
+}
